Code.Terraform:
```hcl
resource "aws_iam_policy" "scoped_marketplace_subscribe" {
  name = "scoped-marketplace-subscribe"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Effect   = "Allow"
      Action   = ["aws-marketplace:Subscribe"]
      Resource = ["arn:aws:aws-marketplace::123456789012:product/approved-product-id"]  # FIX: scope to specific products
    }]
  })
}
